}

private static boolean isADocumentStructure(String html) {
    if (html == null || html.trim().isEmpty()) {
        return false;
    }

    // Normalize whitespace and convert to lowercase for comparison
    String normalized = html.toLowerCase().trim();

    // Check if it starts with document structure tags (html, head elements)
    // This indicates it's a full HTML document rather than a body fragment
    normalized = normalized.replaceAll("\\s+", " ");

    // Look for these structural tags appearing as root-level elements in the input
    // If the HTML starts with <html or contains <head as a top level tag, it's a document
    String trimmed = normalized.trim();

    // Check if the input starts with <html tag (after optional whitespace)
    if (trimmed.startsWith("<html")) {
        return true;
    }

    // Check if the input contains <head> at the document root level (not nested deeply)
    // We need to be more careful to avoid false positives with <head> nested deep in content
    // For the test case, <html><head>... should be caught by first condition, but let's be more specific

    // The most reliable way is to check if the root element after parsing would be html instead of body
    // But we need to parse as document to see that, so let's parse as document and check structure
    org.jsoup.nodes.Document doc = org.jsoup.Jsoup.parse(html, "", Parser.htmlParser());

    // If the document has significant structural elements (html, head), it's not pure body HTML
    // Check if the document has a non-empty head or if the structure suggests it's a full document
    if (doc.head() != null && doc.head().childNodeSize() > 0) {
        // Has content in head, indicating it's a full document
        return true;
    }

    // The root element is always html for a document, but for body fragments, 
    // we only care about the content that would go in body
    // Check if the html element has direct children other than body (like head)
    org.jsoup.nodes.Element docElement = doc.child(0); // should be html
    if (docElement != null && docElement.tagName().equalsIgnoreCase("html")) {
        int nonBodyChildren = 0;
        for (org.jsoup.nodes.Node child : docElement.childNodes()) {
            if (child instanceof org.jsoup.nodes.Element) {
                String tagName = ((org.jsoup.nodes.Element) child).tagName();
                if (!tagName.equalsIgnoreCase("body")) {
                    nonBodyChildren++;
                }
            }
        }
        // If there are non-body children of html (like head), it's a full document
        if (nonBodyChildren > 0) {
            return true;
        }
    }

    return false;
}

