/**
 Test if the input body HTML has only tags and attributes allowed by the Whitelist. Useful for form validation.
 <p>The input HTML should still be run through the cleaner to set up enforced attributes, and to tidy the output.
 <p>Assumes the HTML is a body fragment (i.e. will be used in an existing HTML document body.)
 @param bodyHtml HTML to test
 @param whitelist whitelist to test against
 @return true if no tags or attributes were removed; false otherwise
 @see #clean(String, org.jsoup.safety.Whitelist)
 */
public static boolean isValid(String bodyHtml, Whitelist whitelist) {
    // Parse using regular document parser to see if it looks like a full document
    if (bodyHtml != null && !bodyHtml.trim().isEmpty()) {
        org.jsoup.nodes.Document docAsDocument = Jsoup.parse(bodyHtml);

        // Check if the parsed document has the structure of a full HTML document
        // i.e., html element with head and/or body as children (not just content inside body)
        org.jsoup.nodes.Element htmlEl = docAsDocument.child(0);  // should be html element for full documents
        if (htmlEl != null && htmlEl.tagName().equalsIgnoreCase("html")) {
            // If the html element has a head child with content, it's definitely a full document
            org.jsoup.nodes.Element headEl = docAsDocument.head();
            if (headEl != null && headEl.childNodeSize() > 0) {
                return false;   // Full document with content in head is not body fragment
            }

            // If the html element has multiple direct children (not just one body), 
            // it might be a full document structure
            if (htmlEl.children().size() > 1 || 
                (htmlEl.children().size() == 1 && !htmlEl.children().get(0).tagName().equalsIgnoreCase("body"))) {
                return false;   // Complex document structure is not just body content
            }
        }
    }

    // Now parse as body fragment and validate using cleaner
    org.jsoup.nodes.Document doc = parseBodyFragment(bodyHtml, "");
    return new Cleaner(whitelist).isValid(doc);
}

