/**
 Test if the input body HTML has only tags and attributes allowed by the Whitelist. Useful for form validation.
 <p>The input HTML should still be run through the cleaner to set up enforced attributes, and to tidy the output.
 <p>Assumes the HTML is a body fragment (i.e. will be used in an existing HTML document body.)
 @param bodyHtml HTML to test
 @param whitelist whitelist to test against
 @return true if no tags or attributes were removed; false otherwise
 @see #clean(String, org.jsoup.safety.Whitelist)
 */
public static boolean isValid(String bodyHtml, Whitelist whitelist) {
    // Check if the original input looks like a full HTML document structure
    if (bodyHtml != null && !bodyHtml.trim().isEmpty()) {
        String lower = bodyHtml.toLowerCase().trim();

        // Check for various document structure indicators that suggest this is not a body fragment
        // If starts with html tag or contains document structure significant elements
        if (lower.startsWith("<html")) {
            return false;
        }

        // Also check for the specific pattern of full document structure with head and body
        // A string that has both <head> and <body> tags is likely a complete document
        int htmlTagIndex = lower.indexOf("<html");
        int headTagIndex = lower.indexOf("<head");
        int bodyTagIndex = lower.indexOf("<body");

        // If we have html, head, and body tags in the same string, it's likely a full document
        if (htmlTagIndex != -1 && headTagIndex != -1 && bodyTagIndex != -1) {
            return false;
        }
    }

    org.jsoup.nodes.Document doc = parseBodyFragment(bodyHtml, "");
    return new Cleaner(whitelist).isValid(doc);
}

